`,paraId:84,tocIndex:9},{value:"\u2B06 back to top",paraId:85,tocIndex:9},{value:"6.1",paraId:86,tocIndex:10},{value:" ",paraId:87,tocIndex:10},{value:"\u6CE8\u610F:",paraId:87,tocIndex:10},{value:" ECMA-262 \u5B9A\u4E49\u4E86",paraId:87,tocIndex:10},{value:"block",paraId:87,tocIndex:10},{value:"\u4F5C\u4E3A\u4E00\u7EC4\u8BED\u53E5\u7684\u5757. \u51FD\u6570\u58F0\u660E\u4E0D\u662F\u8BED\u53E5. ",paraId:87,tocIndex:10},{value:"Read ECMA-262's note on this issue",paraId:87,tocIndex:10},{value:".",paraId:87,tocIndex:10},{value:`// bad\r
