`,paraId:102,tocIndex:10},{value:"6.6",paraId:103,tocIndex:10},{value:" \u5C06\u53C2\u6570\u9ED8\u8BA4\u503C\u653E\u5728\u6700\u540E.",paraId:104,tocIndex:10},{value:`// bad\r
