`,paraId:105,tocIndex:10},{value:"6.7",paraId:106,tocIndex:10},{value:" \u4E0D\u8981\u4F7F\u7528 Function \u6784\u9020\u51FD\u6570\u521B\u5EFA\u51FD\u6570. eslint: ",paraId:107,tocIndex:10},{value:"no-new-func",paraId:107,tocIndex:10},{value:"\u539F\u56E0\uFF1A\u6B64\u65B9\u5F0F\u521B\u5EFA\u51FD\u6570\u548C\u5BF9\u5B57\u7B26\u4E32\u4F7F\u7528 eval()\u4E00\u6837\u4F1A\u4EA7\u751F\u6F0F\u6D1E.",paraId:108,tocIndex:10},{value:`// bad\r
